import { useState } from 'react'
import type { HTMLDsButtonUnfilledElement, MenuItemData } from '@ds-mo/ui'
import { DsButtonUnfilled, DsMenu } from '@ds-mo/ui/react'

const choices: MenuItemData[] = [
  { label: 'Overview', value: 'overview' },
  { label: 'Map', value: 'map' },
  { label: 'Timeline', value: 'timeline' },
]

export function ViewMenu() {
  const [selectedValue, setSelectedValue] = useState('overview')
  const [open, setOpen] = useState(false)
  const [initialFocusVisible, setInitialFocusVisible] = useState(false)
  const selected = choices.find(item => item.value === selectedValue) ?? choices[0]
  const items = choices.map(item => ({ ...item, isSelected: item.value === selectedValue }))

  function focusTrigger() {
    requestAnimationFrame(() => {
      const trigger = document.querySelector<HTMLDsButtonUnfilledElement>('#view-menu-trigger')
      trigger?.setFocus()
    })
  }

  return (
    <>
      <DsButtonUnfilled
        id="view-menu-trigger"
        label={`View · ${selected.label}`}
        haspopup="menu"
        controls="view-menu"
        expanded={open}
        onDsClick={event => {
          setInitialFocusVisible(event.detail.detail === 0)
          setOpen(current => !current)
        }}
      />
      <DsMenu
        id="view-menu"
        anchorId="view-menu-trigger"
        menuLabel="Choose view"
        items={items}
        open={open}
        initialFocusVisible={initialFocusVisible}
        onDsClose={() => setOpen(false)}
        onDsSelect={event => {
          setSelectedValue(event.detail.value ?? selectedValue)
          setOpen(false)
          focusTrigger()
        }}
      />
    </>
  )
}

import { Component } from '@angular/core'
import type { HTMLDsButtonUnfilledElement, MenuItemData } from '@ds-mo/ui'
import { DsButtonUnfilled } from '@ds-mo/ui/angular/ds-button-unfilled'
import { DsMenu } from '@ds-mo/ui/angular/ds-menu'

const choices: MenuItemData[] = [
  { label: 'Overview', value: 'overview' },
  { label: 'Map', value: 'map' },
  { label: 'Timeline', value: 'timeline' },
]

@Component({
  selector: 'app-view-menu',
  standalone: true,
  imports: [DsButtonUnfilled, DsMenu],
  templateUrl: './view-menu.component.html',
})
export class ViewMenuComponent {
  selectedValue = 'overview'
  open = false
  initialFocusVisible = false

  get selectedLabel() {
    return choices.find(item => item.value === this.selectedValue)?.label ?? choices[0].label
  }

  get menuItems() {
    return choices.map(item => ({ ...item, isSelected: item.value === this.selectedValue }))
  }

  toggleMenu(event: CustomEvent<MouseEvent>) {
    this.initialFocusVisible = event.detail.detail === 0
    this.open = !this.open
  }

  selectView(event: CustomEvent<MenuItemData>) {
    this.selectedValue = event.detail.value ?? this.selectedValue
    this.open = false
    requestAnimationFrame(() => {
      const trigger = document.querySelector<HTMLDsButtonUnfilledElement>('#view-menu-trigger')
      trigger?.setFocus()
    })
  }
}
